    row_id      TEXT    NOT NULL,
    payload     JSONB   NOT NULL DEFAULT '{}',
    created_at  BIGINT  NOT NULL DEFAULT now_ms(),
    PRIMARY KEY (id, created_at)          -- partition key must appear in PK
) PARTITION BY RANGE (created_at);

