        RAISE EXCEPTION 'p_price on sales_order_lines is immutable after creation.';
    END IF;
    IF NEW.s_price IS DISTINCT FROM OLD.s_price THEN
        RAISE EXCEPTION 's_price on sales_order_lines is immutable after creation.';
    END IF;
