import "../../database/types/schema";
import { PostgrestMaybeSingleResponse } from "@supabase/supabase-js";
import { md5 } from "../../utils/md5";
import { now } from "../../help";
import { Packet } from "../../utils/packet";
import { compileAPIS } from "../../help";


compileAPIS({
    "/auth": {
        async GET(packet: Packet) {
            if (packet.req.header('handshake')) {
                return await login(packet);
            }
            return await AutoConnect(packet);
        },
        async POST(packet: Packet) {
            if (packet.req.header('handshake'))
                return await approveLogin(packet);
        }
    }
})
async function AutoConnect(packet: Packet) {
    const session = await packet.loadSession();
    if (!session) return packet.json('SESSION_NOT_FOUND', 404);
    if (session.logged) {
        if (Number(session.expire) < now(true)) {
            session.logged = false;
            await packet.saveSession();
            return packet.json('SESSION_EXPIRED', 401);
        }
        return packet.json('CONNECTED', 200);
    } else {

    }
    return packet.json('NOT_CONNECTED', 401);
}

async function login(packet: Packet) {
    //const session = packet.session;
    const username = packet.req.header('username');
    if (!username) return packet.json("USERID", 404);
    const { data: user, error, status, statusText }: PostgrestMaybeSingleResponse<Users> = await packet.db.from('users').select('*').eq('name', username).maybeSingle();
    if (statusText !== 'OK' || error) return packet.json('DB_CONNECTION_ERROR', 500);
    if (!user) return packet.json("NOT_REGISTERED", 404);
    const s_id = packet.req.header('S-ID');
    if (!s_id) return packet.json("SESSION_ID", 404);
    const pwdSuffix = crypto.randomUUID().toString().slice(-8);
    const session: Sessions = Object.assign(packet.session || {}, <Sessions>{
        username: username,
        cert: md5(user.pwd + pwdSuffix),
        pwd_suffix: pwdSuffix,
        logged: false,
        role: user.role,
        cid: user.cid,
        handshake_time: now(true),
        expire: now(true) + 1000 * 60 * 60 * 24 * 7,
        IP: packet.req.ip,
        created_at: now(true),
        id: s_id,
        uid: user.id,
    });

    if (await packet.saveSession(session)) {
        return packet.json({ pwdSuffix, handshakeTime: session.handshake_time, username: session.username }, 200, md5(user.pwd));
    } else {
        return packet.json('DB_CONNECTION_ERROR', 500);
    }
}
async function approveLogin(packet: Packet) {
    const session = await packet.loadSession();
    if (!session) return packet.json('SESSION_NOT_FOUND', 404);
    const data = packet.data;
    if (typeof data === 'object') {
        if (data.handshakeTime != session.handshake_time) {
            return packet.json('INVALID_HANDSHAKE', 401);
        }
        if (data.pwdSuffix != session.pwd_suffix) {
            return packet.json('INVALID_HANDSHAKE', 401);
        }
        session.logged = true;
        if (await packet.saveSession()) {
            return packet.json('CONNECTED', 200);
        } else {
            return packet.json('DB_CONNECTION_ERROR', 500);
        }
    }
    return packet.json('INVALID_HANDSHAKE', 401);
}


