import { compileAPIS, Packet } from "../../help";


compileAPIS({
    POST: {
        async "/batch"(packet: Packet) {
            const { operations } = packet.body;

            const results = [];
            for (const op of operations) {
                let result;
                if (op.action === "upsert") {
                    result = await packet.db.from(op.table).upsert(op.data);
                } else if (op.action === "delete") {
                    result = await packet.db.from(op.table).delete().eq("id", op.id);
                }
                results.push({ table: op.table, action: op.action, error: result?.error });
            }

            return packet.json({ results }, 200);
        }
    }
});

import { compileAPIS, md5, Packet } from "../../help";
import { } from "@supabase/supabase-js";


compileAPIS({
  GET: {
    async "/stream/changes"(packet: Packet) {
      const { res } = packet;
      let since = Number(packet.query.since || 0);
      const x = await packet.keeyAlive(200, "application/json", packet.session?.cert || md5("achour"))!;
      if (!x) return;
      const interval = setInterval(async () => {
        const cutoff = new Date(new Date(since).getTime() + 1).toISOString();
        const { data, error } = await packet.db
          .from("audit_log")
          .select("*")
          .gt("created_at", cutoff)
          .order("created_at", { ascending: true })
          .limit(1000) as { data: AuditLogRow[], error: any, statusText: string };

        if (error) {
          console.error(error);
          return;
        }

        if (data?.length) {
          since = data[data.length - 1].created_at;
          x.write(data);
        }
      }, 5000);

      res.on("close", () => clearInterval(interval));
      const promise = new Promise((resl, rej) => {
        res.on("close", () => rej(new Error("Connection closed")));
      });
      return promise;
    }
  }
});

import "../../database/types/schema";
import { compileAPIS } from "../../help";
import { Packet } from "../../utils/packet";
import { ERPHelper } from "../../database/adapters/ErpHelper";

compileAPIS({
    // Standard paginated fetch of the aggregated stock view
    '/inventory/:page': {
        async GET(packet: Packet) {
            const page = parseInt(packet.params.page) || 1;

            // There is no dedicated RPC for full table pagination, so we securely read the view
            let { result } = await packet.request('v_products_stock', {
                employee: "admin",
                admin: ({ req }) => req
                    .select('*')
                    .order('name', { ascending: true })
                    .range((page - 1) * 100, (page * 100) - 1)
            });

            return packet.validate(result);
        }
    },

    // Quick filter check for stock alerts using RPC
    '/inventory/alerts/:status': {
        async GET(packet: Packet) {
            const status = packet.params.status;

            if (status === 'LOW_STOCK') {
                // Using exactly the generated RPC function for low stock!
                const erp = new ERPHelper(packet.db);
                const lowStockRows = await erp.lowStockList();
                return packet.json(lowStockRows, 200);
            }

            // Fallback for OUT_OF_STOCK, IN_STOCK since our RPC only handles the critical low_stock
            let { result } = await packet.request('v_products_stock', {
                employee: "admin",
                admin: ({ req }) => req
                    .select('*')
                    .eq('stock_status', status)
                    .order('name', { ascending: true })
            });

            return packet.validate(result);
        }
    },

    // Total valuation widget using RPC Dashboard Summary
    '/inventory/valuation': {
        async GET(packet: Packet) {
            const erp = new ERPHelper(packet.db);
            const summary = await erp.dashboardSummary();

            if (ERPHelper.isErr(summary)) return packet.json(summary, 500);

            return packet.json({ gross_inventory_value: summary.inventory_value }, 200);
        }
    }
});

