import "../../database/types/schema";
import { compileAPIS } from "../../help";
import { Packet } from "../../utils/packet";

compileAPIS({
    // ---------------------------------------------------------
    // PRODUCTS API
    // ---------------------------------------------------------
    '/products': {
        /**
         * GET: List products
         * Logic: Admin/Employee see all non-deleted, Customers see only active non-deleted
         */
        async GET(packet: Packet) {
            const since = packet.query.since;
            let { result } = await packet.request('products', {
                employee: "admin",
                admin: ({ req }) => req.select('*').eq('deleted', false).gt('updated_at', since),
                customer: ({ req }) => req.select('*').eq('active', true).eq('deleted', false).gt('updated_at', since)
            });

            return packet.validate(result);
        },

        /**
         * POST: Create product (Admin/Employee only)
         */
        async POST(packet: Packet) {
            //check for missing fields
            const { name, price } = packet.body;
            if (!name || !price) return packet.json('MISSING_FIELDS', 400);
            let { result } = await packet.request('products', {
                employee: "admin",
                admin: ({ req, body }) => req.insert({ ...body }).select().single()
            });

            return packet.validate(result);
        }
    },

    '/product/:id': {
        /**
         * GET: Single product detail
         */
        async GET(packet: Packet) {
            const { result, error } = await packet.request('products', {
                employee: "admin",
                admin: ({ req, params }) => req.select('*').eq('id', params.id).maybeSingle(),
                customer: ({ req, params }) => req.select('*').eq('id', params.id).eq('active', true).maybeSingle()
            });

            if (error) return packet.json('DB_CONNECTION_ERROR', 500);

            if (!result) return packet.json('NOT_FOUND', 404);
            return packet.json(result, 200, packet.session?.cert);
        },

        /**
         * PATCH: Update product (Admin/Employee only)
         */
        async PATCH(packet: Packet) {
            const { name, price } = packet.body;
            if (!name || !price) return packet.json('MISSING_FIELDS', 400);
            const { result } = await packet.request('products', {
                employee: "admin",
                admin: ({ req, params, body }) => {
                    return req.update(<Products>{ ...body }).eq('id', params.id).select().maybeSingle();
                }
            });

            if (result?.error) return packet.json('UPDATE_FAILED', 400);
            if (!result?.data) return packet.json('NOT_FOUND', 404);

            return packet.json(result?.data, 200, packet.session?.cert);
        },

        /**
         * DELETE: Remove product (Admin/Employee only)
         */
        async DELETE(packet: Packet) {
            const { result } = await packet.request('products', {
                employee: "admin",
                admin: ({ req, params }) => {
                    return req.delete().eq('id', params.id).select().maybeSingle();
                }
            });

            if (result?.error) return packet.json('DELETE_FAILED', 500);
            if (!result?.data) return packet.json('NOT_FOUND', 404);

            return packet.json({ deleted: true, id: packet.params.id }, 200, packet.session?.cert);
        }
    },
    '/product/:id/images': {
        async GET(packet: Packet) {
            const { result } = await packet.request('assets', {
                employee: "admin",
                admin: ({ req, params }) => req.select('*').eq('product_id', params.id),
                customer: ({ req, params }) => req.select('*').eq('product_id', params.id).eq('active', true)
            });

            return packet.validate(result);
        },
        async POST(packet: Packet) {
            const { result } = await packet.request('assets', {
                employee: "admin",
                admin: ({ req, body }) => req.insert({ ...body }).select().single()
            });

            return packet.validate(result);
        }
    },
    '/product/:id/images/:imageId': {
        async DELETE(packet: Packet) {
            const { result } = await packet.request('assets', {
                employee: "admin",
                admin: ({ req, params }) => req.delete().eq('id', params.imageId).select().maybeSingle()
            });

            if (!result?.data) { result.error = 'NOT_FOUND'; result.errorCode = 404; }
            return packet.validate(result);
        }
    }
});

