// this the api for assets images/text/videos/audios/files/ etc get from folder ./assets 

import "../../database/types/schema";
import { args, compileAPIS, eargs } from "../../help";
import { Packet } from "../../utils/packet";
import Bun from "bun";
import multer from 'multer';

// 1. Configure where to save files temporarily
const upload = multer({ dest: './assets/' });
compileAPIS({
    '/assets/:id': {
        async GET(packet: Packet) {
            // get file from ./assets folder no database
            // first get the file  path from table assets
            // if not found return 404
            // if found return file
            const { result } = await packet.request('assets', {
                employee: "admin",
                admin: ({ req, params }) => req.select('*').eq('id', params.id).maybeSingle(),
                customer: ({ req, params }) => req.select('*').eq('id', params.id).eq('active', true).maybeSingle()
            });

            if (result?.error) return packet.json('DB_FETCH_ERROR', 500);
            if (!result?.data) return packet.json('NOT_FOUND', 404);
            // get file from ./assets folder no database
            // first get the file  path from table assets
            // if not found return 404
            // if found return file
            const file = Bun.file(result?.data.path);
            if (!file.exists()) return packet.json('NOT_FOUND', 404);
            return packet.send(file)

        }
    },
    '/assets/upload': {
        /**
         * POST: Upload file to ./assets (Admin/Employee only)
         */
        async POST(packet: Packet) {
            const session = await packet.loadSession();
            let g: args<unknown> | eargs<unknown>;
            if (session?.role !== 'admin' && session?.role !== 'employee') {
                g = <eargs<any>>{ error: 'UNAUTHORIZED', errorCode: 401 };
            }
            const file = await packet.saveFile();
            if (file.error) g = <eargs<any>>{ error: file.error, errorCode: file.code };
            else g = <args<any>>{ result: file.record, errorCode: 201 };
            return packet.validate(g);
        }
    },



});

