export async function auditMiddleware(req: Request, res: Response, next: NextFunction) {
  const packet = getPacket(req, res);
  const method = packet.method;
  if (["POST", "PUT", "PATCH", "DELETE"].includes(method)) {
    const result = await next();

    await packet.db.from("audit_log").insert({
      table_name: packet.params.table,
      operation: method,
      row_id: packet.params.id || "unknown",
      payload: packet.body,
      created_at: now(false)
    });

    return result;
  }
  return next();
}

import { NextFunction, Request, Response } from "express";
import { getPacket, Packet } from "../utils/packet";
import { decryptData } from "../utils/cryptography";

import { now } from "../help";

async function decrypte(packet: Packet): Promise<void> {
    if (packet.method === 'GET' || packet.method === 'OPTIONS' || packet.method === 'HEAD' || packet.method === 'TRACE' || packet.method === 'CONNECT' || packet.method === 'PATCH') {
        packet.data = packet.body;
        return;
    }
    let crypteable = false;
    try {
        const session = await packet.loadSession()
        if (!session) return packet.serviceWraper('SESSION_NOT_FOUND', {});
        if (session.expire && (Number(session.expire) < now(true))) {
            return packet.serviceWraper('SESSION_EXPIRED', {});
        }
        packet.setSession(session, false);
        const body = packet.body;
        crypteable = typeof body === 'object' && 'data' in body && 'iv' in body;
        if (crypteable) {
            const data = await decryptData(body, session.cert);
            packet.data = JSON.parse(data) as HandshakeData;
        } else {
            packet.data = body;
        }
    } catch (error) {
        if (crypteable) return packet.serviceWraper('CRYPTO', { 'error': error }, 401);
    }

}
export async function jsonDecrypter(req: Request, res: Response, next: NextFunction) {
    const packet = getPacket(req, res);
    await decrypte(packet);
    if (!packet.isClosed) next();
}

import fs from 'fs';
import path from 'path';

function loadEnv() {
    const envPath = path.resolve(process.cwd(), '.env');

    if (!fs.existsSync(envPath)) return;

    const envFile = fs.readFileSync(envPath, 'utf-8');
    const lines = envFile.split('\n').filter((line: string) => line.trim() && !line.startsWith('#'));

    lines.forEach((line: string) => {
        const delimiterIndex = line.indexOf('=');
        if (delimiterIndex <= 0) return;

        const key = line.slice(0, delimiterIndex).trim();
        let value = line.slice(delimiterIndex + 1).trim();

        // Remove wrapping quotes if they exist ("value" or 'value')
        if ((value.startsWith('"') && value.endsWith('"')) ||
            (value.startsWith("'") && value.endsWith("'"))) {
            value = value.slice(1, -1);
        } else {
            // Only attempt casting if the value was NOT wrapped in quotes.
            // (If a user writes PORT="3000", they explicitly want it as a string).
            value = <any>castValue(value);
        }

        //if (!process.env.hasOwnProperty(key)) {
        process.env[key] = value;
        //}
    });
}

function castValue(val: string) {
    // 1. Check for Boolean
    if (val.toLowerCase() === 'true') return true;
    if (val.toLowerCase() === 'false') return false;

    // 2. Check for Number (Only if it doesn't start with 0, to prevent "0123" from becoming "83" in octal)
    if (/^-?\d+$/.test(val) && (val.length === 1 || val[0] !== '0')) {
        return parseInt(val, 10);
    }

    // Check for Floating Point Numbers
    if (/^-?\d+\.\d+$/.test(val)) {
        return parseFloat(val);
    }

    // 3. Check for Date (Matches YYYY-MM-DD or ISO 8601 formats)
    if (/^\d{4}-\d{2}-\d{2}(T|\s)/.test(val) || /^\d{4}-\d{2}-\d{2}$/.test(val)) {
        const parsedDate = new Date(val);
        if (!isNaN(parsedDate.getTime())) {
            return parsedDate;
        }
    }

    // 4. Fallback to String
    return val;
}

loadEnv();

import { Request, Response } from 'express';
import * as cookieParser from 'cookie-parser';

interface CookieOptions {
    httpOnly?: boolean;
    secure?: boolean;
    signed?: boolean;
    sameSite?: 'lax' | 'strict' | 'none' | boolean;
    path?: string;
    maxAge?: number;
    domain?: string;
}
export const SID: 'S-ID' = 'S-ID';
class CookieManager {
    private readonly secret: string;
    private readonly isProduction: boolean;

    constructor(
        secret: string = process.env.SESSION_SECRET || 'DEFAULT_SECRET',
        isProduction: boolean = process.env.NODE_ENV === 'production'
    ) {
        this.secret = secret;
        this.isProduction = isProduction;
    }

    /**
     * Default configuration focused on security and cross-origin compatibility.
     */
    private get defaultOptions(): CookieOptions {
        return {
            httpOnly: false,
            // In TS, sameSite must be lowercase 'none' | 'lax' | 'strict'
            sameSite: !this.isProduction ? 'none' : 'lax',
            secure: this.isProduction,
            signed: true,
            path: '/',
            maxAge: 100000 * 60 * 60 * 24 // 24 hours

        };
    }

    /**
     * Bakes a new cookie into the response.
     */
    public set<T = string | object>(
        res: Response,
        name: string,
        value: T,
        options: CookieOptions = {}
    ) {
        const finalOptions = { ...this.defaultOptions, ...options };

        // SameSite=none REQUIRES Secure=true in modern browsers
        if (finalOptions.sameSite === 'none' && !finalOptions.secure) {
            console.warn(`[CookieManager] Security Risk: SameSite='none' requires Secure=true.`);
        }

        res.cookie(name, value, finalOptions);
        return value;
    }

    /**
     * Retrieves and validates a signed cookie.
     * Returns null if the signature is invalid or cookie is missing.
     */
    public get<T = string | object>(req: Request, name: string): T | null {
        // 1. Check signedCookies (populated by cookie-parser middleware)
        const signedValue = req.signedCookies?.[name];
        if (!signedValue) {
            // 2. Manual fallback if middleware is not used or hasn't run
            const rawValue = req.cookies?.[name];
            if (rawValue) {
                const unsigned = cookieParser.signedCookie(rawValue, this.secret);
                if (unsigned !== false) return unsigned as unknown as T;
            }
        }
        return null;
    }

    /**
     * Removes the cookie from the client.
     */
    public clear(res: Response, name: string, options: CookieOptions = {}): void {
        // Note: When clearing, options must match the 'path' and 'domain' used to set it.
        const { signed, ...clearOptions } = this.defaultOptions;
        res.clearCookie(name, { ...clearOptions, ...options });
    }
    SID(req: Request, res: Response) {
        let sid = this.get<string>(req, SID) || req.header(SID) as any;
        if (!sid) {
            sid = this.set<string>(res, SID, sid = crypto.randomUUID(), { domain: 'os.dz' });
            if (!req.signedCookies) req.signedCookies = {};
            req.signedCookies[SID] = sid;
        }
        res.setHeader(SID, sid);
        return sid;
    }
}

export default new CookieManager(process.env.COOKIE_SECRET, false);

